/**
 * Build script: Bundle agent .md files into a JS module.
 * Eliminates all runtime filesystem access in the serverless function.
 *
 * Usage: node scripts/bundle-agents.js
 * Output: api/_lib/agents-data.js
 */
import { readFile, readdir, writeFile } from 'fs/promises'
import { existsSync } from 'fs'
import { join, dirname } from 'path'
import { fileURLToPath } from 'url'

const __dirname = dirname(fileURLToPath(import.meta.url))
const ROOT = join(__dirname, '..')
const AGENTS_DIR = join(ROOT, 'agents')
const WORKFLOWS_DIR = join(AGENTS_DIR, 'workflows')
const OUTPUT = join(ROOT, 'api', '_lib', 'agents-data.js')

function escapeTemplateLiteral(str) {
  return str.replace(/\\/g, '\\\\').replace(/`/g, '\\`').replace(/\$\{/g, '\\${')
}

async function main() {
  // Read system prompt
  const systemContent = await readFile(join(AGENTS_DIR, 'system.md'), 'utf-8')

  // Read all agent .md files
  const agentFiles = (await readdir(AGENTS_DIR))
    .filter(f => f.endsWith('.md') && f !== 'system.md' && f !== 'README.md')
    .sort()

  const agents = []
  for (const file of agentFiles) {
    const content = await readFile(join(AGENTS_DIR, file), 'utf-8')
    agents.push({ id: file.replace('.md', ''), content })
  }

  // Read workflow files
  let workflows = []
  if (existsSync(WORKFLOWS_DIR)) {
    const workflowFiles = (await readdir(WORKFLOWS_DIR))
      .filter(f => f.endsWith('.md'))
      .sort()

    for (const file of workflowFiles) {
      const content = await readFile(join(WORKFLOWS_DIR, file), 'utf-8')
      workflows.push({ id: file.replace('.md', ''), content })
    }
  }

  // Generate JS module
  let out = `// AUTO-GENERATED by scripts/bundle-agents.js — DO NOT EDIT\n\n`

  out += `export const SYSTEM_PROMPT = \`${escapeTemplateLiteral(systemContent)}\`\n\n`

  out += `export const AGENT_FILES = [\n`
  for (const a of agents) {
    out += `  { id: ${JSON.stringify(a.id)}, content: \`${escapeTemplateLiteral(a.content)}\` },\n`
  }
  out += `]\n\n`

  out += `export const WORKFLOW_FILES = [\n`
  for (const w of workflows) {
    out += `  { id: ${JSON.stringify(w.id)}, content: \`${escapeTemplateLiteral(w.content)}\` },\n`
  }
  out += `]\n`

  await writeFile(OUTPUT, out, 'utf-8')

  console.log(`[bundle-agents] Generated ${OUTPUT}`)
  console.log(`  Agents: ${agents.length} (${agents.map(a => a.id).join(', ')})`)
  console.log(`  Workflows: ${workflows.length}`)
}

main().catch(err => {
  console.error('[bundle-agents] FATAL:', err)
  process.exit(1)
})
